import{_ as e,a as l,b as n}from"./chunks/配置容量限制.DkdWbdOw.js";import{_ as i,o as t,c as r,a2 as d}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"Cloudflare R2 Kanalı Ekleme","description":"","frontmatter":{},"headers":[],"relativePath":"tr-TR/upload/cloudflare-r2.md","filePath":"tr-TR/upload/cloudflare-r2.md","lastUpdated":1781962217000}'),o={name:"tr-TR/upload/cloudflare-r2.md"};function u(m,a,s,k,c,b){return t(),r("div",null,[...a[0]||(a[0]=[d('<h1 id="cloudflare-r2-kanalı-ekleme" tabindex="-1">Cloudflare R2 Kanalı Ekleme <a class="header-anchor" href="#cloudflare-r2-kanalı-ekleme" aria-label="Permalink to &quot;Cloudflare R2 Kanalı Ekleme&quot;">​</a></h1><h2 id="ne-zaman-uygun" tabindex="-1">Ne Zaman Uygun? <a class="header-anchor" href="#ne-zaman-uygun" aria-label="Permalink to &quot;Ne Zaman Uygun?&quot;">​</a></h2><p>Cloudflare R2&#39;yi şu durumlarda kullanın:</p><ul><li>ImgBed siteniz zaten Cloudflare üzerinde çalışıyorsa ve dosyaları aynı Cloudflare hesabındaki bir R2 bucket içinde saklamak istiyorsanız.</li><li>Ayrı bir S3 endpoint, access key ve secret key yapılandırmak istemiyorsanız.</li><li>Okuma ve yazma işlemlerinin Worker veya Pages R2 binding üzerinden en az kurulumla çalışmasını istiyorsanız.</li></ul><p>Kısaca:</p><p>R2 kanalı ImgBed yönetim panelinde elle oluşturulmaz. Önce Cloudflare projesine bir R2 bucket bağlamanız gerekir ve binding değişken adı tam olarak <code>img_r2</code> olmalıdır.</p><h2 id="baslamadan-once-gerekenler" tabindex="-1">Başlamadan Önce Gerekenler <a class="header-anchor" href="#baslamadan-once-gerekenler" aria-label="Permalink to &quot;Başlamadan Önce Gerekenler&quot;">​</a></h2><ul><li>Cloudflare hesabı.</li><li>Önceden oluşturulmuş bir R2 bucket.</li><li>ImgBed&#39;in dağıtıldığı Cloudflare projesini yönetme yetkisi.</li></ul><h2 id="cloudflare-da-yapılandırma" tabindex="-1">Cloudflare&#39;da Yapılandırma <a class="header-anchor" href="#cloudflare-da-yapılandırma" aria-label="Permalink to &quot;Cloudflare&#39;da Yapılandırma&quot;">​</a></h2><h3 id="_1-r2-bucket-olusturun" tabindex="-1">1. R2 Bucket Oluşturun <a class="header-anchor" href="#_1-r2-bucket-olusturun" aria-label="Permalink to &quot;1. R2 Bucket Oluşturun&quot;">​</a></h3><ol><li>Cloudflare Dashboard&#39;a giriş yapın.</li><li><code>R2 Object Storage</code> bölümünü açın.</li><li>Create bucket düğmesine tıklayın.</li><li>Bucket adı seçin, örneğin <code>imgbed</code>.</li></ol><p>Yüklenen dosyalar bu bucket içinde saklanır.</p><p><img src="'+e+'" alt="R2 bucket oluşturma" loading="lazy"></p><h3 id="_2-bucket-ı-imgbed-projesine-baglayın" tabindex="-1">2. Bucket&#39;ı ImgBed Projesine Bağlayın <a class="header-anchor" href="#_2-bucket-ı-imgbed-projesine-baglayın" aria-label="Permalink to &quot;2. Bucket&#39;ı ImgBed Projesine Bağlayın&quot;">​</a></h3><p>Binding konumu dağıtım türüne göre değişir:</p><table tabindex="0"><thead><tr><th>Dağıtım Türü</th><th>Binding Konumu</th></tr></thead><tbody><tr><td>Pages</td><td>Current Pages project -&gt; Settings -&gt; Functions -&gt; R2 bucket bindings</td></tr><tr><td>Worker</td><td>Current Worker -&gt; Settings -&gt; Bindings -&gt; R2 bucket bindings</td></tr></tbody></table><p>Binding eklerken önemli alanlar şunlardır:</p><table tabindex="0"><thead><tr><th>Alan</th><th>Değer</th></tr></thead><tbody><tr><td>Variable name</td><td><code>img_r2</code></td></tr><tr><td>R2 bucket</td><td>Oluşturduğunuz bucket&#39;ı seçin.</td></tr></tbody></table><p>Değişken adı tam olarak <code>img_r2</code> olmalıdır. R2 dosyalarını yükleme, okuma ve silme işlemlerinin tamamı bu binding adına bağlıdır.</p><h3 id="_3-projeyi-yeniden-dagıtın" tabindex="-1">3. Projeyi Yeniden Dağıtın <a class="header-anchor" href="#_3-projeyi-yeniden-dagıtın" aria-label="Permalink to &quot;3. Projeyi Yeniden Dağıtın&quot;">​</a></h3><p>Binding&#39;i kaydettikten sonra ImgBed&#39;i yeniden dağıtın. Böylece Worker veya Pages runtime <code>img_r2</code> değerine erişebilir.</p><h2 id="imgbed-de-ne-goreceksiniz" tabindex="-1">ImgBed&#39;de Ne Göreceksiniz? <a class="header-anchor" href="#imgbed-de-ne-goreceksiniz" aria-label="Permalink to &quot;ImgBed&#39;de Ne Göreceksiniz?&quot;">​</a></h2><p>R2 binding kullanılabilir hale geldikten sonra şurayı açın:</p><ol><li>Sistem Ayarları.</li><li>Yükleme Ayarları.</li><li><code>Cloudflare R2</code> kanalı.</li></ol><p>Sistem otomatik olarak tek bir sabit kanal oluşturur:</p><table tabindex="0"><thead><tr><th>Alan</th><th>Sabit Değer</th></tr></thead><tbody><tr><td>Kanal adı</td><td><code>Cloudflare R2</code></td></tr><tr><td>Kanal türü</td><td><code>cfr2</code></td></tr><tr><td>Depolama modu</td><td><code>binding</code></td></tr><tr><td>Yapılandırma kaynağı</td><td>Environment binding</td></tr></tbody></table><p>Bu sabit bir binding kanalıdır. Oluşturmak için Add Channel düğmesine basmanız gerekmez ve normal kanallar gibi silinemez.</p><h2 id="yonetim-panelinde-duzenlenebilen-alanlar" tabindex="-1">Yönetim Panelinde Düzenlenebilen Alanlar <a class="header-anchor" href="#yonetim-panelinde-duzenlenebilen-alanlar" aria-label="Permalink to &quot;Yönetim Panelinde Düzenlenebilen Alanlar&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Alan</th><th>Ne işe yarar</th><th>Zorunlu</th></tr></thead><tbody><tr><td>Enable channel</td><td>R2&#39;nin yükleme seçiminde kullanılıp kullanılmayacağını belirler.</td><td>Evet</td></tr><tr><td>Account ID</td><td>Yalnızca kota limitleri açıksa ve resmi R2 kullanımını sorgulamak istiyorsanız gerekir.</td><td>Kota limitleri açıksa önerilir</td></tr><tr><td>Bucket name</td><td>Yalnızca kota limitleri açıksa ve resmi R2 kullanımını sorgulamak istiyorsanız gerekir.</td><td>Kota limitleri açıksa önerilir</td></tr><tr><td>Quota limit</td><td>Bu R2 kanalının kapasiteye göre yükleme seçiminde dikkate alınıp alınmayacağını belirler.</td><td>Hayır</td></tr><tr><td>Threshold</td><td>Kullanım belirtilen yüzdeye ulaşınca bu kanala yazmayı durdurur.</td><td>Kota limitleri açıksa evet</td></tr></tbody></table><p>Account ID değerini Cloudflare dashboard&#39;daki hesap bilgisi panelinden kopyalayabilirsiniz. ImgBed&#39;in R2 kota kullanımını sorgulamasını ve uygulamasını istiyorsanız doldurun.</p><p><img src="'+l+'" alt="Account ID alma" loading="lazy"></p><h2 id="kurulum-adımları" tabindex="-1">Kurulum Adımları <a class="header-anchor" href="#kurulum-adımları" aria-label="Permalink to &quot;Kurulum Adımları&quot;">​</a></h2><ol><li>Cloudflare&#39;da bir R2 bucket oluşturun.</li><li>ImgBed projesinin Cloudflare ayarlarını açın.</li><li>R2 bucket binding ekleyin.</li><li><code>Variable name</code> alanını <code>img_r2</code> olarak ayarlayın.</li><li>Oluşturduğunuz R2 bucket&#39;ı seçin.</li><li>Binding&#39;i kaydedin ve ImgBed&#39;i yeniden dağıtın.</li><li>ImgBed -&gt; System Settings -&gt; Upload Settings bölümüne dönün.</li><li><code>Cloudflare R2</code> kanalının göründüğünü ve etkin olduğunu doğrulayın.</li></ol><p>R2&#39;nin kapasiteye göre yükleme seçiminde yer almasını istiyorsanız quota limit&#39;i etkinleştirin, ardından kaydetmeden önce Account ID, bucket name, quota limit ve threshold değerlerini girin.</p><p><img src="'+n+'" alt="Kota limitlerini yapılandırma" loading="lazy"></p><h2 id="nasıl-kontrol-edilir" tabindex="-1">Nasıl Kontrol Edilir? <a class="header-anchor" href="#nasıl-kontrol-edilir" aria-label="Permalink to &quot;Nasıl Kontrol Edilir?&quot;">​</a></h2><ul><li>Sabit <code>Cloudflare R2</code> kanalı Yükleme Ayarları&#39;nda görünür.</li><li>Kanal kartında etkin olduğu görülür.</li><li>Küçük bir test dosyası başarıyla yüklenir ve dönen bağlantı normal şekilde açılır.</li><li>Dosya açılırken <code>R2 database binding is not configured</code> hatası dönüyorsa runtime <code>img_r2</code> binding değerini almamıştır. Cloudflare&#39;daki binding adını kontrol edin ve projeyi yeniden dağıtın.</li></ul>',37)])])}const p=i(o,[["render",u]]);export{h as __pageData,p as default};
